#include <bits/stdc++.h>
using namespace std;

long long nthFaithfulNumber(int N) {
    vector<long long> powers(23);  // 23 is enough as 7^23 exceeds long long

    // Calculate powers of 7
    powers[0] = 1;
    for(int i = 1; i < 23; i++) {
        powers[i] = powers[i-1] * 7;
    }

    long long result = 0;
    int pos = 0;

    while(N > 0) {
        if(N & 1) {
            result += powers[pos];
        }
        pos++;
        N >>= 1;
    }

    return result;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n;
        cin >> n;
        cout << nthFaithfulNumber(n) << endl;
    }
    return 0;
}

